+/// Generate a unique session ID for a writer instance.
+fn generate_session_id() -> String {
+    use sha2::{Digest, Sha256};
+    use std::process;
+
+    let now = chrono::Utc::now();
+    let pid = process::id();
+    let thread_id = format!("{:?}", thread::current().id());
